function chartPointValue(point, key, index) {
  const raw = key ? point?.[key] : point?.value;
  const numeric = Number(raw);
  return Number.isFinite(numeric) ? numeric : index + 1;
}

function chartPointLabel(point, index) {
  return fallbackText(point?.label ?? point?.name ?? point?.x, `Point ${index + 1}`);
}

function renderChart(props = {}) {
  const series = safeArray(props.series);
  const chartType = normalizeVariant(props.chartType, "bar", ["bar", "line", "area", "donut"]);
  const values = series.map((point, index) => chartPointValue(point, props.yKey, index));
  const maxValue = Math.max(1, ...values);
  const status =
    props.error || props.loading || props.empty || series.length === 0
      ? element(
          "p",
          { role: props.error ? "alert" : "status" },
          props.error ? text(props.error) : props.loading ? "Loading chart." : "No chart data.",
        )
      : null;
  const bars = series.map((point, index) => {
    const value = values[index];
    const height = Math.max(4, Math.round((value / maxValue) * 80));
    return element("rect", {
      className: "jami-chart-mark",
      x: String(12 + index * 24),
      y: String(92 - height),
      width: "14",
      height: String(height),
      role: "img",
      "aria-label": `${chartPointLabel(point, index)}: ${value}`,
    });
  });
  return element(
    "figure",
    {
      className: "jami-chart",
      role: "group",
      "aria-label": props.ariaLabel ?? props.title ?? "Chart",
      "data-chart-type": chartType,
      "aria-busy": props.loading ? "true" : undefined,
    },
    props.title ? element("figcaption", { className: "jami-chart-title" }, text(props.title)) : null,
    props.description ? element("p", { className: "jami-chart-description" }, text(props.description)) : null,
    status,
    series.length
      ? element(
          "svg",
          { className: "jami-chart-svg", role: "img", viewBox: "0 0 160 100", "aria-label": props.title ?? "Chart values" },
          element("line", { className: "jami-chart-axis", x1: "8", x2: "152", y1: "92", y2: "92" }),
          ...bars,
        )
      : null,
    series.length
      ? element(
          "table",
          { className: "jami-chart-table" },
          element("thead", {}, element("tr", {}, element("th", { scope: "col" }, "Label"), element("th", { scope: "col" }, "Value"))),
          element(
            "tbody",
            {},
            ...series.map((point, index) =>
              element("tr", {}, element("td", {}, chartPointLabel(point, index)), element("td", {}, displayValue(values[index]))),
            ),
          ),
        )
      : null,
  );
}

