  return h(
    RadixDialog.Root,
    { defaultOpen: Boolean(open), modal },
    h(
      RadixDialog.Trigger,
      compactProps({
        ...triggerProps,
        ref,
        className: joinClassNames("jami-dialog-trigger", triggerClassName),
