      fallbackText(triggerLabel, `Open ${dialogTitle}`),
    ),
    h(
      RadixDialog.Content,
      compactProps({
        className: joinClassNames("jami-dialog-content", className, contentClassName),
        "aria-describedby": descriptionId,
      }),
      h(RadixDialog.Title, { className: "jami-dialog-title" }, dialogTitle),
      description
        ? h(RadixDialog.Description, { id: descriptionId, className: "jami-dialog-description" }, text(description))
