export const JamiSelect = React.forwardRef(function JamiSelect(
  { label, ariaLabel, items, defaultValue, disabled = false, placeholder, className, triggerClassName, contentClassName } = {},
  ref,
) {
  const selectItems = safeItems(items, [
    { value: "solo", label: "Solo" },
    { value: "business", label: "Business" },
  ]);
  const initialValue = defaultValue ?? itemValue(selectItems[0], 0, "option");
  const selectedItem = selectItems.find((item, index) => itemValue(item, index, "option") === initialValue) ?? selectItems[0];
  return h(
    "div",
    { className: joinClassNames("jami-select", className) },
    label ? h("span", { className: "jami-select-label" }, text(label)) : null,
    h(
      RadixSelect.Root,
      { defaultValue: initialValue, disabled },
      h(
        RadixSelect.Trigger,
        compactProps({
          ref,
          className: joinClassNames("jami-select-trigger", triggerClassName),
          "aria-label": ariaLabel ?? label ?? "Select option",
        }),
        h(RadixSelect.Value, { placeholder: placeholder ?? "Select an option" }),
        h("span", { className: "jami-select-selected" }, itemLabel(selectedItem, 0, "Option")),
        h(RadixSelect.Icon, { "aria-hidden": "true" }, "v"),
      ),
      h(
        RadixSelect.Content,
        { className: joinClassNames("jami-select-content", contentClassName) },
        h(
          RadixSelect.Viewport,
          { className: "jami-select-viewport" },
          ...selectItems.map((item, index) =>
            h(
              RadixSelect.Item,
              {
                key: itemValue(item, index, "option"),
                className: "jami-select-item",
                value: itemValue(item, index, "option"),
                disabled: Boolean(item.disabled),
              },
              h(RadixSelect.ItemText, null, text(itemLabel(item, index, "Option"))),
            ),
          ),
        ),
      ),
    ),
  );
});

